// Physical KeyboardEvent.code values, relative to a US QWERTY keyboard, that creators pass to
// J.onControlPress / J.onControlRelease. Left/right modifier pairs are addressed by their folded
// names ("Shift", not "ShiftLeft").
export const KEY_CODES = [
	// letters
	"KeyA",
	"KeyB",
	"KeyC",
	"KeyD",
	"KeyE",
	"KeyF",
	"KeyG",
	"KeyH",
	"KeyI",
	"KeyJ",
	"KeyK",
	"KeyL",
	"KeyM",
	"KeyN",
	"KeyO",
	"KeyP",
	"KeyQ",
	"KeyR",
	"KeyS",
	"KeyT",
	"KeyU",
	"KeyV",
	"KeyW",
	"KeyX",
	"KeyY",
	"KeyZ",
	// top-row digits
	"Digit0",
	"Digit1",
	"Digit2",
	"Digit3",
	"Digit4",
	"Digit5",
	"Digit6",
	"Digit7",
	"Digit8",
	"Digit9",
	// function keys
	"F1",
	"F2",
	"F3",
	"F4",
	"F5",
	"F6",
	"F7",
	"F8",
	"F9",
	"F10",
	"F11",
	"F12",
	// whitespace / editing
	"Space",
	"Enter",
	"Tab",
	"Backspace",
	"Delete",
	"Escape",
	// modifiers (left/right fold to these)
	"Shift",
	"Control",
	"Alt",
	"Meta",
	"CapsLock",
	// arrows
	"ArrowUp",
	"ArrowDown",
	"ArrowLeft",
	"ArrowRight",
	// navigation cluster
	"Home",
	"End",
	"PageUp",
	"PageDown",
	"Insert",
	// punctuation
	"Backquote",
	"Minus",
	"Equal",
	"BracketLeft",
	"BracketRight",
	"Backslash",
	"Semicolon",
	"Quote",
	"Comma",
	"Period",
	"Slash",
	"IntlBackslash",
	// numpad
	"Numpad0",
	"Numpad1",
	"Numpad2",
	"Numpad3",
	"Numpad4",
	"Numpad5",
	"Numpad6",
	"Numpad7",
	"Numpad8",
	"Numpad9",
	"NumpadAdd",
	"NumpadSubtract",
	"NumpadMultiply",
	"NumpadDivide",
	"NumpadDecimal",
	"NumpadEnter",
	"NumLock",
	"ScrollLock",
	"PrintScreen",
	"Pause",
] as const;

// A single physical key. The `| (string & {})` at the call site keeps legacy names ("q") and
// "+" combos ("Control+KeyB") compiling while editors still suggest these values.
export type KeyCode = (typeof KEY_CODES)[number];
